internal fun localizedNameForRegion_normal_cho(
  query: Int,
  script: Int,
  region: Int,
  variant: Int,
): String? {
  if (region != 0 || script != 0 || variant != 0) {
    return null
  }
  return when (query) {
    297 -> "United States" // US
    else -> null
  }
}

